#include<bits/stdc++.h>
using namespace std;
int a[2600][2600],n,m;
int q[2600]={0},p[2600];
bool f[1001];
int main(){
	cin>>n>>m;
    int inf=1e7;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            if(i==j){
                continue;
            }
            a[i][j]=inf;
        }
    }
	for(int i=1;i<=m;i++){
		int x,y,z;
		cin>>x>>y>>z;
        if(a[x][y]>z){
		a[x][y]=z;
		a[y][x]=z;}
	}
	for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            for(int k=1;k<=n;k++){
                if(a[j][k]>a[j][i]+a[i][k]) a[j][k]=a[j][i]+a[i][k];
            }
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            cout<<a[i][j]<<' ';
        }cout<<endl;
    }
	return 0;
}
